SELECT observation_id, value_a, value_b
FROM observations
WHERE observation_id > 5;

SELECT 
  (SELECT AVG(value_a) FROM observations WHERE created_by = 0) - 
  (SELECT SUM(value_b) FROM observations WHERE created_by = 0) AS diff;

SELECT obs.observation_id, ds.source_name
FROM observations obs
JOIN data_sources ds ON obs.source_id = ds.source_id;

SELECT DISTINCT first_category 
FROM observations 
WHERE first_category IS NOT NULL;
